// n8n: CODE - Scheduling webhook normalize
// After TRG - Webhook (scheduling-slots or scheduling-confirmed)

const raw = $input.first().json || {};
const body = raw.body || raw;
const sessionId = String(body.session_id || body.sessionId || raw.session_id || '').trim();

if (!sessionId) {
  throw new Error('session_id required in webhook body.');
}

return [
  {
    json: {
      session_id: sessionId,
      webhook_kind: raw.webhook_kind || body.webhook_kind || 'scheduling',
    },
  },
];

// n8n: CODE - Build candidate slot mail (scheduling — thread reply)
// Triggered by: POST /webhook/talent/scheduling-slots { session_id }
// Input: HTTP - SB GET session (slots) — reads proposed_slots from Supabase
//
// Gmail node settings:
//   Resource:   thread
//   Operation:  reply
//   Thread ID:  {{ $json.gmail_thread_id }}
//   Message ID: {{ $json.gmail_message_id }}
//   Email Type: HTML
//   Message:    {{ $json.mail_body_html }}

function extractConfig(row) {
  const out = {};
  if (!row || typeof row !== 'object') return out;
  if (row.config && typeof row.config === 'object') Object.assign(out, row.config);
  for (const [k, v] of Object.entries(row)) {
    if (k.startsWith('config.') && v != null && String(v).trim()) {
      out[k.slice(7)] = String(v).trim();
    }
  }
  return out;
}

function pickNodeJson(...names) {
  for (const name of names) {
    if (!name) continue;
    try {
      const raw = $(name).first().json;
      if (raw && typeof raw === 'object') return raw;
    } catch (_) {}
  }
  return null;
}

function pickSessionRow() {
  const fetchRaw = pickNodeJson(
    'HTTP - SB GET session (slots)',
    'HTTP - SB GET session (scheduling)',
    'HTTP - Fetch Session',
    'HTTP - Fetch Session1'
  );
  const row = Array.isArray(fetchRaw) ? fetchRaw[0] : fetchRaw;
  if (row?.id) return row;

  const input = $input.first().json;
  if (input?.id) return input;
  return {};
}

function normalizeSlots(raw) {
  if (!raw) return [];
  let slots = raw;
  if (typeof slots === 'string') {
    try {
      slots = JSON.parse(slots);
    } catch (_) {
      return [];
    }
  }
  if (!Array.isArray(slots)) return [];
  return slots
    .map((s, i) => ({
      start_iso: s.start_iso || s.start || '',
      end_iso: s.end_iso || s.end || '',
      label: s.label || s.start_iso || `Slot ${i + 1}`,
    }))
    .filter((s) => s.start_iso || s.label);
}

const session = pickSessionRow();
const cfg = {
  ...extractConfig(session),
  ...(typeof session.config === 'object' ? session.config : {}),
};

const threadId = String(session.gmail_thread_id || '').trim();
const msgId = String(session.gmail_message_id || '').trim();
if (!threadId || threadId.startsWith('draft-')) {
  throw new Error('gmail_thread_id missing — shortlist mail must run first.');
}
if (!msgId) {
  throw new Error('gmail_message_id missing — PATCH after shortlist/result mail first.');
}

const portalBase = String(
  cfg.portal_base_url || cfg.candidate_portal_base || 'https://talent-acquisition-six.vercel.app'
).replace(/\/+$/, '');

const pickPortal = portalBase + '/candidate-pick.html';
const sessionId = String(session.id || '').trim();
if (!sessionId) {
  throw new Error('session id missing from Supabase row.');
}

const slots = normalizeSlots(session.proposed_slots);
if (!slots.length) {
  throw new Error(
    'proposed_slots empty on session — interviewer must submit slots on interviewer.html first.'
  );
}

const schedulingLink = pickPortal + '?session=' + encodeURIComponent(sessionId);

const candidateEmail = String(session.candidate_email || '').trim();
const score = session.score != null ? session.score : '—';
const org = String(cfg.organization_name || 'Talent Acquisition Team');
const role = String(cfg.requisition_title || session.requisition_id || 'the role');

const mailBody =
  `Hi,\n\n` +
  `Congratulations! You passed our technical assessment for ${role} (score: ${score}/100).\n\n` +
  `Next step: choose your interview time:\n` +
  `${schedulingLink}\n\n` +
  `Best regards,\n${org}`;

const slotListHtml = slots
  .map(
    (s) =>
      `<li style="margin:6px 0;">${String(s.label || s.start_iso || '').replace(/</g, '&lt;')}</li>`
  )
  .join('');

const mailBodyHtml =
  `<!DOCTYPE html>
<html><head><meta charset="UTF-8"></head>
<body style="margin:0;padding:0;background:#f1f5f9;font-family:Segoe UI,Arial,sans-serif;">
  <table width="100%" cellpadding="0" cellspacing="0" style="background:#f1f5f9;padding:32px 16px;">
    <tr><td align="center">
      <table width="100%" style="max-width:560px;background:#fff;border-radius:12px;padding:32px;">
        <tr><td style="color:#334155;font-size:15px;line-height:1.6;">
          <p style="margin:0 0 8px;font-size:12px;letter-spacing:.08em;text-transform:uppercase;color:#64748b;">── Interview Scheduling ──</p>
          <p>Hi,</p>
          <p><strong>Congratulations!</strong> You passed our technical assessment for <strong>${role.replace(/</g, '&lt;')}</strong> (score: <strong>${score}/100</strong>).</p>
          <p>Next step — pick your interview time:</p>
          <ul style="padding-left:20px;color:#475569;">${slotListHtml}</ul>
          <p style="text-align:center;margin:28px 0;">
            <a href="${schedulingLink}" style="display:inline-block;background:#4f46e5;color:#fff;text-decoration:none;padding:14px 28px;border-radius:8px;font-weight:600;">Choose interview time</a>
          </p>
          <p style="font-size:13px;color:#64748b;">Or copy this link: ${schedulingLink}</p>
          <p>Best regards,<br>${org.replace(/</g, '&lt;')}</p>
        </td></tr>
      </table>
    </td></tr>
  </table>
</body></html>`;

return [
  {
    json: {
      ...session,
      config: cfg,
      session_id: sessionId,
      gmail_thread_id: threadId,
      gmail_message_id: msgId,
      scheduling_link: schedulingLink,
      proposed_slots: slots,
      slots,
      mail_body: mailBody,
      mail_body_html: mailBodyHtml,
      mail_stage: 'scheduling',
      candidate_email: candidateEmail,
      score,
      requisition_title: role,
    },
  },
];

// n8n: CODE - Merge Gmail reply response
// Paste AFTER any Gmail "Thread → Reply" node.
// Prepares Supabase PATCH so the next reply chains to this message.
//
// Wire:
//   Gmail Thread Reply → this node → HTTP PATCH session gmail message
//
// Set HTTP PATCH node:
//   URL:  {{ $json._gmail_patch_url }}
//   Body: {{ $json._gmail_patch_body }}

function pickSessionContext() {
  const names = [
    'CODE - Build assessment result mail',
    'CODE - Build candidate slot mail',
    'CODE - Build interview confirmed mail',
    'CODE - Build Gmail thread reply context',
    'CODE - Prep scheduling from PASS',
    'CODE - Parse Result',
    'HTTP - Fetch Session',
  ];
  let merged = {};
  for (const name of names) {
    try {
      merged = { ...merged, ...($input.first().json || {}), ...$(name).first().json };
    } catch (_) {}
  }
  return merged;
}

function resolveGmailPayload(input, ...mailNodeNames) {
  if (input && (input.id || input.messageId || input.threadId || input.thread_id)) {
    return input;
  }
  for (const name of mailNodeNames) {
    if (!name) continue;
    try {
      const raw = $(name).first().json;
      if (raw && (raw.id || raw.messageId || raw.threadId || raw.thread_id)) return raw;
    } catch (_) {}
  }
  return input || {};
}

const gmail = resolveGmailPayload(
  $input.first().json,
  'MAIL - Candidate pitch mail',
  'MAIL - Candidate pitch mail1',
  'MAIL - Notify candidate',
  'MAIL - Notify candidate1'
);
const ctx = pickSessionContext();
const cfg = ctx.config || {};

const msgId = String(gmail.id || gmail.messageId || '').trim();
const threadId = String(gmail.threadId || gmail.thread_id || ctx.gmail_thread_id || '').trim();

const sessionId = String(
  ctx.session_id || ctx.session_db_id || ctx.id || ''
).trim();

const patchReady = Boolean(sessionId && threadId && msgId);
if (!patchReady) {
  return [
    {
      json: {
        ...ctx,
        _gmail_patch_skipped: true,
        _gmail_patch_skip_reason: [
          !sessionId ? 'missing session_id' : null,
          !threadId ? 'missing gmail_thread_id' : null,
          !msgId ? 'missing gmail message id' : null,
        ]
          .filter(Boolean)
          .join('; '),
        _gmail_patch_url: '',
        _gmail_patch_body: {},
      },
    },
  ];
}

const b = String(cfg.supabase_url || '').replace(/\/+$/, '');
const tb = cfg.table_assessment_sessions || 'assessment_sessions';

return [
  {
    json: {
      ...ctx,
      gmail_message_id: msgId,
      gmail_thread_id: threadId,
      _gmail_patch_url: `${b}/rest/v1/${tb}?id=eq.${encodeURIComponent(sessionId)}`,
      _gmail_patch_body: {
        gmail_message_id: msgId,
        gmail_thread_id: threadId,
        updated_at: new Date().toISOString(),
      },
    },
  },
];

// n8n: CODE - Scheduling confirmed from session
// After HTTP GET session (scheduling-confirmed webhook)
// Replaces WAIT + Parse candidate choice for frontend-driven flow

function pickSessionRow() {
  const raw = $input.first().json;
  const row = Array.isArray(raw) ? raw[0] : raw?.session_row || raw;
  if (row?.id) return row;
  try {
    const prev = $('HTTP - SB GET session (confirmed)').first().json;
    return Array.isArray(prev) ? prev[0] : prev;
  } catch (_) {}
  return {};
}

const session = pickSessionRow();
const cfg =
  typeof session.config === 'string'
    ? (() => {
        try {
          return JSON.parse(session.config);
        } catch (_) {
          return {};
        }
      })()
    : session.config || {};

let slot = session.chosen_slot;
if (typeof slot === 'string') {
  try {
    slot = JSON.parse(slot);
  } catch (_) {
    slot = null;
  }
}

if (!slot || (!slot.start_iso && !slot.label)) {
  throw new Error('chosen_slot missing on session — candidate must confirm on candidate-pick.html first.');
}

const start_iso = slot.start_iso || slot.start || '';
const end_iso = slot.end_iso || slot.end || '';
const slot_label = slot.label || start_iso || 'Selected slot';

return [
  {
    json: {
      ...session,
      config: cfg,
      session_id: session.id,
      candidate_email: session.candidate_email,
      interviewer_email: cfg.interviewer_email || session.interviewer_email || '',
      proposed_slots: session.proposed_slots || [],
      selected_slot: slot,
      selected_slot_label: slot_label,
      slot_label,
      chosen_slot: slot_label,
      start_iso,
      end_iso,
      score: session.score,
      requisition_title: cfg.requisition_title || session.requisition_id,
    },
  },
];

// n8n: CODE - Build interview confirmed mail (thread reply)
// Place AFTER: candidate picks slot / calendar event created
// Place BEFORE: Gmail Thread Reply node
//
// Input should include: candidate_email, selected slot, session row or thread ids

function pickSessionRow() {
  const names = [
    'HTTP - Fetch Session',
    'CODE - Parse candidate slot',
    'CODE - Prep scheduling from PASS',
    'CODE - Build candidate slot mail',
  ];
  for (const name of names) {
    try {
      const raw = $(name).first().json;
      const row = raw?.session_row || (Array.isArray(raw) ? raw[0] : raw);
      if (row?.gmail_thread_id || row?.id) return row;
    } catch (_) {}
  }
  return {};
}

const base = $input.first().json;
const session = pickSessionRow();
const cfg = { ...(session.config || {}), ...(base.config || {}) };

const threadId = String(session.gmail_thread_id || base.gmail_thread_id || '').trim();
const msgId = String(session.gmail_message_id || base.gmail_message_id || '').trim();

if (!threadId) throw new Error('gmail_thread_id missing — cannot reply in candidate thread.');
if (!msgId) throw new Error('gmail_message_id missing — send scheduling reply first.');

const role = String(cfg.requisition_title || base.requisition_title || 'the role');
const org = String(cfg.organization_name || 'Talent Acquisition Team');
const slotLabel = String(
  base.selected_slot_label ||
    base.slot_label ||
    base.chosen_slot ||
    base.start_iso ||
    'your selected time'
);
const sessionId = String(session.id || base.session_id || '');

const mailBodyHtml = `<!DOCTYPE html>
<html><head><meta charset="UTF-8"></head>
<body style="margin:0;padding:0;background:#f1f5f9;font-family:Segoe UI,Arial,sans-serif;">
  <table width="100%" cellpadding="0" cellspacing="0" style="background:#f1f5f9;padding:24px 16px;">
    <tr><td align="center">
      <table width="100%" style="max-width:560px;background:#fff;border-radius:12px;padding:28px;">
        <tr><td style="color:#334155;font-size:15px;line-height:1.6;">
          <p style="margin:0 0 8px;font-size:12px;letter-spacing:.08em;text-transform:uppercase;color:#64748b;">── Interview Confirmed ──</p>
          <p>Hi,</p>
          <p>Your interview for <strong>${role.replace(/</g, '&lt;')}</strong> is confirmed.</p>
          <p><strong>Time:</strong> ${slotLabel.replace(/</g, '&lt;')}</p>
          <p>Please join on time. If you need to reschedule, reply to this email.</p>
          <p>Best regards,<br>${org.replace(/</g, '&lt;')}</p>
        </td></tr>
      </table>
    </td></tr>
  </table>
</body></html>`;

return [
  {
    json: {
      ...base,
      session_id: sessionId,
      gmail_thread_id: threadId,
      gmail_message_id: msgId,
      mail_body_html: mailBodyHtml,
      mail_stage: 'confirmed',
      candidate_email: base.candidate_email || session.candidate_email,
      config: cfg,
    },
  },
];

// n8n: CODE - Build interviewer confirmed mail (interviewer thread reply)
// Place AFTER: CAL - Create interview event
// Place BEFORE: Gmail Thread Reply (interviewer)

function pickSessionRow() {
  const names = ['HTTP - Fetch Session', 'CODE - Parse candidate choice', 'CODE - Prep scheduling from PASS'];
  for (const name of names) {
    try {
      const raw = $(name).first().json;
      const row = raw?.session_row || (Array.isArray(raw) ? raw[0] : raw);
      if (row?.id) return row;
    } catch (_) {}
  }
  return {};
}

const base = $input.first().json;
const session = pickSessionRow();
const cfg = { ...(session.config || {}), ...(base.config || {}) };

const threadId = String(session.interviewer_gmail_thread_id || base.interviewer_gmail_thread_id || '').trim();
const msgId = String(session.interviewer_gmail_message_id || base.interviewer_gmail_message_id || '').trim();

if (!threadId) throw new Error('interviewer_gmail_thread_id missing — send interviewer pitch mail first.');
if (!msgId) throw new Error('interviewer_gmail_message_id missing — PATCH after interviewer pitch mail.');

const role = String(cfg.requisition_title || base.requisition_title || 'the role');
const candidateEmail = String(base.candidate_email || session.candidate_email || '');
const slotLabel = String(
  base.selected_slot_label || base.slot_label || base.chosen_slot || base.start_iso || 'scheduled time'
);
const org = String(cfg.organization_name || 'Talent Acquisition Team');

const mailBodyHtml = `<!DOCTYPE html>
<html><head><meta charset="UTF-8"></head>
<body style="margin:0;padding:0;background:#f1f5f9;font-family:Segoe UI,Arial,sans-serif;">
  <table width="100%" cellpadding="0" cellspacing="0" style="background:#f1f5f9;padding:24px 16px;">
    <tr><td align="center">
      <table width="100%" style="max-width:560px;background:#fff;border-radius:12px;padding:28px;">
        <tr><td style="color:#334155;font-size:15px;line-height:1.6;">
          <p style="margin:0 0 8px;font-size:12px;letter-spacing:.08em;text-transform:uppercase;color:#64748b;">── Interview Confirmed ──</p>
          <p>Hello,</p>
          <p>Interview scheduled for <strong>${candidateEmail.replace(/</g, '&lt;')}</strong> — <strong>${role.replace(/</g, '&lt;')}</strong>.</p>
          <p><strong>Time:</strong> ${slotLabel.replace(/</g, '&lt;')}</p>
          <p>Calendar invite has been created. Candidate confirmation sent in their thread.</p>
          <p>Best regards,<br>${org.replace(/</g, '&lt;')}</p>
        </td></tr>
      </table>
    </td></tr>
  </table>
</body></html>`;

return [
  {
    json: {
      ...base,
      session_id: session.id || base.session_id,
      interviewer_email: base.interviewer_email || cfg.interviewer_email,
      interviewer_gmail_thread_id: threadId,
      interviewer_gmail_message_id: msgId,
      mail_body_html: mailBodyHtml,
      config: cfg,
    },
  },
];
